import { EXTRA_VENUES } from "./venues-extra.js";
import { EXTRA_VENUES2 } from "./venues-extra2.js";
import { EXTRA_VENUES3 } from "./venues-extra3.js";
import { EXTRA_VENUES4 } from "./venues-extra4.js";
// Merge with later sources overriding earlier ones on duplicate id, so the most
// recent curated database (database5 → EXTRA_VENUES4) wins over older stub data.
{
  const merged = new Map<string, Venue>();
  for (const v of [...VENUES, ...EXTRA_VENUES, ...EXTRA_VENUES2, ...EXTRA_VENUES3, ...EXTRA_VENUES4]) {
    merged.set(v.id, v);
  }
  VENUES.length = 0;
  VENUES.push(...merged.values());
}

export function getVenues(regionCode?: string, category?: VenueCategory): Venue[] {
  return VENUES.filter((v) => {
    if (regionCode && v.regionCode !== regionCode.toUpperCase()) return false;
    if (category && v.category !== category) return false;
    return true;
  });
}

export function getVenuesForCounsel(regionCode: string): string {
  const venues = getVenues(regionCode);
  if (venues.length === 0) return "";

  const grouped: Partial<Record<VenueCategory, Venue[]>> = {};
  for (const v of venues) {
    if (!grouped[v.category]) grouped[v.category] = [];
    grouped[v.category]!.push(v);
  }

  const lines: string[] = [];
  const categoryLabels: Record<VenueCategory, string> = {
    shops: "Shops & Boutiques",
    dining: "Dining Venues",
    activities: "Activities & Events",
    accommodations: "Accommodations",
    transport: "Private Transport",
  };

  for (const [cat, list] of Object.entries(grouped) as [VenueCategory, Venue[]][]) {
    lines.push(`${categoryLabels[cat]}:`);
    for (const v of list) {
      lines.push(`  - ${v.name} (${v.subcategory}): ${v.description} [Etiquette: ${v.etiquetteTip}]`);
    }
  }

  return lines.join("\n");
}
